import React, { useState } from 'react';
import axios from 'axios';
import { LogIn, Mail, Lock } from 'lucide-react';

const Login = () => {
  const [formData, setFormData] = useState({ email: '', password: '' });
  const [message, setMessage] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      // Talking to your successful Backend!
      const res = await axios.post('http://localhost:5000/api/auth/login', formData);
      setMessage(`Welcome back, ${res.data.user.name}!`);
      localStorage.setItem('token', res.data.token); // Save the session
    } catch (err) {
      setMessage(err.response?.data?.msg || 'Login Failed');
    }
  };

  return (
    <div className="flex items-center justify-center min-h-screen bg-gray-100">
      <div className="p-8 bg-white shadow-2xl rounded-2xl w-96 border-t-4 border-blue-600">
        <div className="flex justify-center mb-6 text-blue-600">
          <LogIn size={48} />
        </div>
        <h2 className="text-2xl font-bold text-center text-gray-800 mb-6">QuadSolutions Login</h2>
        
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="relative">
            <Mail className="absolute left-3 top-3 text-gray-400" size={20} />
            <input
              type="email"
              placeholder="Email Address"
              className="w-full pl-10 pr-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              onChange={(e) => setFormData({...formData, email: e.target.value})}
              required
            />
          </div>
          <div className="relative">
            <Lock className="absolute left-3 top-3 text-gray-400" size={20} />
            <input
              type="password"
              placeholder="Password"
              className="w-full pl-10 pr-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              onChange={(e) => setFormData({...formData, password: e.target.value})}
              required
            />
          </div>
          <button className="w-full bg-blue-600 text-white py-2 rounded-lg font-semibold hover:bg-blue-700 transition duration-300">
            Sign In
          </button>
        </form>
        {message && <p className="mt-4 text-center text-sm font-medium text-blue-600">{message}</p>}
      </div>
    </div>
  );
};

export default Login;
